// Compliant: Direct use of boolean expressions
func processUser(user User) {
    if user.IsActive {
        fmt.Println("User is active")
    }

    if user.IsVerified {
        sendWelcomeEmail(user)
    }

    enabled := user.IsEnabled
    verified := user.IsVerified

    // Clean boolean logic
    if user.HasPermission() && !user.IsBlocked() {
        grantAccess()
    }

    // Direct return
    return user.IsAdmin
}

// Compliant: Clean boolean operations
func validateSettings(config Config) bool {
    // Direct boolean logic
    result := config.IsValid && config.IsEnabled

    if config.Debug {
        log.Println("Debug mode enabled")
    }

    // Simple conditional
    var status string
    if config.IsProduction {
        status = "prod"
    } else {
        status = "dev"
    }

    return result
}

